SELECT UPPER(team_name) AS team_name
FROM teams
WHERE league_id = (
  SELECT league_id FROM leagues WHERE league_name = 'Soccer League'
);

SELECT t.team_id, t.team_name
FROM teams t
JOIN team_statistics ts ON t.team_id = ts.team_id
WHERE ts.goal_difference = (
  SELECT MAX(goal_difference) FROM team_statistics
);
